import type { CashVoucherDto } from '../services/kt/models';
import { canShowVoucherEditDelete } from './voucherToolbarActions';
import { isFinalProcessingLevel } from './voucherProcessingLevelDisplay';

export function canViewLedgerFromListRow(
  row: CashVoucherDto,
  canViewLedgerPermission: boolean,
): boolean {
  if (!canViewLedgerPermission) return false;
  return row.status === 'Posted' || isFinalProcessingLevel(row.processingLevel);
}

export function canEditFromListRow(
  row: CashVoucherDto,
  canUpdatePermission: boolean,
): boolean {
  return canUpdatePermission && canShowVoucherEditDelete(row.status, row.processingLevel, false);
}
