import React, { useState } from 'react';
import { ErpListToolbarButton, useDeviceContentSize, useViewMobileLayout } from '@linm-soft/common-components';
import { AnchoredDropdown } from '@linm-soft/common-components';
import styles from '../../styles/erpPage.module.css';

export interface VoucherListToolbarProps {
  testIdPrefix: string;
  onRefresh: () => void;
  canApprove?: boolean;
  approveDisabled?: boolean;
  onApprove?: () => void;
  canViewLedger?: boolean;
  onViewLedger?: () => void;
  canPrint?: boolean;
  onPrint?: () => void;
  canView?: boolean;
  onView?: () => void;
  canEdit?: boolean;
  onEdit?: () => void;
  canCreate?: boolean;
  onCreate?: () => void;
  onEditConfig?: () => void;
}

/** Sticky toolbar — mobile layout matches `CatalogListToolbar` (TaiKhoanPage). */
export const VoucherListToolbar: React.FC<VoucherListToolbarProps> = ({
  testIdPrefix,
  onRefresh,
  canApprove = false,
  approveDisabled = true,
  onApprove,
  canViewLedger = false,
  onViewLedger,
  canPrint = false,
  onPrint,
  canView = false,
  onView,
  canEdit = false,
  onEdit,
  canCreate = false,
  onCreate,
  onEditConfig,
}) => {
  const { isSmall } = useDeviceContentSize();
  const viewMobile = useViewMobileLayout();
  const mobileToolbar = isSmall || viewMobile;
  const [moreOpen, setMoreOpen] = useState(false);

  const refreshBtn = (
    <ErpListToolbarButton
      action="refresh"
      variant="secondary"
      size="sm"
      data-testid={`${testIdPrefix}-toolbar-refresh-btn`}
      onClick={onRefresh}
    />
  );

  const approveBtn = canApprove ? (
    <ErpListToolbarButton
      action="approve"
      variant="secondary"
      size="sm"
      disabled={approveDisabled}
      data-testid={`${testIdPrefix}-batch-approve-btn`}
      onClick={onApprove}
    />
  ) : null;

  const viewLedgerBtn = (
    <ErpListToolbarButton
      action="viewLedger"
      variant="secondary"
      size="sm"
      disabled={!canViewLedger}
      data-testid={`${testIdPrefix}-toolbar-view-ledger-btn`}
      onClick={onViewLedger}
    />
  );

  const printBtn = (
    <ErpListToolbarButton
      action="print"
      variant="secondary"
      size="sm"
      disabled={!canPrint}
      data-testid={`${testIdPrefix}-toolbar-print-btn`}
      onClick={onPrint}
    />
  );

  const configBtn = onEditConfig ? (
    <ErpListToolbarButton
      action="editConfig"
      variant="secondary"
      size="sm"
      data-testid={`${testIdPrefix}-list-config-btn`}
      onClick={onEditConfig}
    />
  ) : null;

  const viewBtn = (
    <ErpListToolbarButton
      action="view"
      variant="secondary"
      size="sm"
      disabled={!canView}
      data-testid={`${testIdPrefix}-toolbar-view-btn`}
      onClick={onView}
    />
  );

  const editBtn = (
    <ErpListToolbarButton
      action="edit"
      variant="secondary"
      size="sm"
      disabled={!canEdit}
      data-testid={`${testIdPrefix}-toolbar-edit-btn`}
      onClick={onEdit}
    />
  );

  const createBtn = canCreate ? (
    <ErpListToolbarButton
      action="create"
      variant="primary"
      size="sm"
      data-testid={`${testIdPrefix}-toolbar-create-btn`}
      onClick={onCreate}
    />
  ) : null;

  const moreItems = (
    <>
      {viewLedgerBtn}
      {printBtn}
      {configBtn}
    </>
  );

  if (mobileToolbar) {
    return (
      <div className={styles.catalogToolbarSticky} data-testid={`${testIdPrefix}-voucher-toolbar`}>
        <div className={styles.catalogToolbarLine1}>
          <div className={styles.catalogToolbarLeft}>
            {refreshBtn}
            {approveBtn}
            <AnchoredDropdown
                isOpen={moreOpen}
                onClose={() => setMoreOpen(false)}
                dropdownTestId={`${testIdPrefix}-toolbar-more-dropdown`}
                width={280}
                anchor={(
                  <ErpListToolbarButton
                    action="more"
                    variant="secondary"
                    size="sm"
                    iconOnly
                    aria-label="Thêm thao tác"
                    data-testid={`${testIdPrefix}-toolbar-more-btn`}
                    onClick={() => setMoreOpen(v => !v)}
                  />
                )}
              >
                <div className={styles.anchoredDropdownBody}>{moreItems}</div>
              </AnchoredDropdown>
          </div>
        </div>
        <div className={styles.catalogToolbarLine2}>
          <div className={styles.catalogToolbarLine2Buttons}>
            {viewBtn}
            {editBtn}
            {createBtn}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.catalogToolbarSticky} data-testid={`${testIdPrefix}-voucher-toolbar`}>
      <div className={styles.catalogToolbarLine1}>
        <div className={styles.catalogToolbarLeft}>
          {refreshBtn}
          {approveBtn}
          {viewLedgerBtn}
          {printBtn}
          {configBtn}
        </div>
        <div className={styles.catalogToolbarRight}>
          {viewBtn}
          {editBtn}
          {createBtn}
        </div>
      </div>
    </div>
  );
};
